INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2625, 205596, 'tt2084970', NULL, 'The Imitation Game', 'The Imitation Game', 'movie', 2014, 'https://image.tmdb.org/t/p/w500/zSqJ1qFq8NXFfi7JeIYMlzyR0dx.jpg', 'https://image.tmdb.org/t/p/original/usuRn9DUKQQr4nBWnrQzlOuZ1Q4.jpg', 'Based on the real life story of legendary cryptanalyst Alan Turing, the film portrays the nail-biting race against time by Turing and his brilliant team of code-breakers at Britain''s top-secret Government Code and Cypher School at Bletchley Park, during the darkest days of World War II.', NULL, NULL, 16.2735, 7.983, 0, 1.12, '2026-07-15 16:46:47', '2026-07-15 16:46:47');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2626, 489, 'tt0119217', NULL, 'Good Will Hunting', 'Good Will Hunting', 'movie', 1997, 'https://image.tmdb.org/t/p/w500/z2FnLKpFi1HPO7BEJxdkv6hpJSU.jpg', 'https://image.tmdb.org/t/p/original/xj1Sv1xm4Y0ydBueGuf10Y9qM0O.jpg', 'Will Hunting is a headstrong, working-class genius who is failing the lessons of life. After one too many run-ins with the law, Will''s last chance is a psychology professor, who might be the only man who can reach him.', NULL, NULL, 16.3966, 8.163, 0, 1.14000000000000012e+00, '2026-07-15 16:46:47', '2026-07-15 16:46:47');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2627, 8162, 'tt0192263', NULL, 'Longitude', 'Longitude', 'tv', 2000, 'https://image.tmdb.org/t/p/w500/e0JjmMSQa0l5iSTsXpSCOdWjSN.jpg', 'https://image.tmdb.org/t/p/original/b258MdHe8P942mJgf5V1bZbTy9c.jpg', 'The fascinating story of John Harrison who, in the 18th century, believed he could make a clock that would work on board a ship—and so solve the problem of finding longitude at sea.', NULL, NULL, 2.2956, 7.0, 0, 1.02, '2026-07-15 16:46:47', '2026-07-15 16:46:47');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2628, 8065, 'tt0478087', NULL, '21', '21', 'movie', 2008, 'https://image.tmdb.org/t/p/w500/efG8Po57alqSlhqHU1lXJ3duG6t.jpg', 'https://image.tmdb.org/t/p/original/u6OCGwhSWhfQX1LZ4NTq0bfcWxs.jpg', 'Ben Campbell is a young, highly intelligent student at M.I.T. who strives to succeed. Wanting a scholarship to transfer to Harvard School of Medicine to become a doctor, Ben learns that he cannot afford the $300,000 tuition as he comes from a poor, working-class background. But one evening, Ben is introduced by his unorthodox math professor to a small but secretive club of five students, Jill, Choi, Kianna, and Fisher, who are being trained by Professor Rosa to count cards at blackjack.', NULL, NULL, 4.082, 6.694, 0, 1.05, '2026-07-15 16:46:47', '2026-07-15 16:46:47');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2629, 381284, 'tt4846340', NULL, 'Hidden Figures', 'Hidden Figures', 'movie', 2016, 'https://image.tmdb.org/t/p/w500/9lfz2W2uGjyow3am00rsPJ8iOyq.jpg', 'https://image.tmdb.org/t/p/original/rfkIeCaIHhN3K5wjJJqKmfUjYp8.jpg', 'The untold story of Katherine G. Johnson, Dorothy Vaughan and Mary Jackson – brilliant African-American women working at NASA and serving as the brains behind one of the greatest operations in history – the launch of astronaut John Glenn into orbit. The visionary trio crossed all gender and race lines to inspire generations to dream big.', NULL, NULL, 10.3994, 8.045, 0, 1.01, '2026-07-15 16:46:47', '2026-07-15 16:46:47');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2630, 9777, 'tt0377107', NULL, 'Proof', 'Proof', 'movie', 2005, 'https://image.tmdb.org/t/p/w500/h5z4JWhaPYMMXhYzwuK7SUgjmMm.jpg', 'https://image.tmdb.org/t/p/original/7WW1qhOdDzYWmjmhIwVt8lc9FCJ.jpg', 'Catherine is a woman in her late twenties who is strongly devoted to her father, Robert, a brilliant and well-known mathematician whose grip on reality is beginning to slip away. As Robert descends into madness, Catherine begins to wonder if she may have inherited her father''s mental illness along with his mathematical genius.', NULL, NULL, 1.465, 6.35, 0, 1.01, '2026-07-15 16:46:47', '2026-07-15 16:46:47');
