INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2632, 46738, 'tt1255953', NULL, 'Incendies', 'Incendies', 'movie', 2010, 'https://image.tmdb.org/t/p/w500/yH6DAQVgbyj72S66gN4WWVoTjuf.jpg', 'https://image.tmdb.org/t/p/original/f3ATwil5vmUeTsogBaMEKbBYBth.jpg', 'A mother''s last wishes send twins Jeanne and Simon on a journey to Middle East in search of their tangled roots. Adapted from Wajdi Mouawad''s acclaimed play, Incendies tells the powerful and moving tale of two young adults'' voyage to the core of deep-rooted hatred, never-ending wars and enduring love.', NULL, NULL, 9.6076, 8.11, 0, 5.01, '2026-07-15 16:46:47', '2026-07-15 16:46:47');
