INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2635, 10220, 'tt0128442', NULL, 'Rounders', 'Rounders', 'movie', 1998, 'https://image.tmdb.org/t/p/w500/mqbMwYGwIChnaCO55h7v8DG8Wwy.jpg', 'https://image.tmdb.org/t/p/original/tgRQsrjBKdic7llxhI7pqLJb8kS.jpg', 'Poker addict Mike McDermott knows the game inside out, but loses his money one night in a game to Russian-American gangster Teddy KGB. Promising his partner Jo he''ll give up, he meets up with best friend Lester ''Worm'' Murphy, just out of prison and owing lots of money to the wrong kind of people. McDermott becomes his co-guarantor and now there''s only one way to raise the money, the pair have to get back into the game.', NULL, NULL, 3.8647, 7.017, 0, 1.01, '2026-07-15 16:46:47', '2026-07-15 16:46:47');
