INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2638, 27461, 'tt0097336', NULL, 'Fat Man and Little Boy', 'Fat Man and Little Boy', 'movie', 1989, 'https://image.tmdb.org/t/p/w500/4CLeeHTMUesP8MCFt5phmdPSS5k.jpg', 'https://image.tmdb.org/t/p/original/5yW6uJ3o4oKyXcuBv5wFcy0IQvc.jpg', 'Assigned to oversee the development of the atomic bomb, Gen. Leslie Groves is a stern military man determined to have the project go according to plan. He selects J. Robert Oppenheimer as the key scientist on the top-secret operation, but the two men clash fiercely on a number of issues. Despite their frequent conflicts, Groves and Oppenheimer ultimately push ahead with two bomb designs — the bigger "Fat Man" and the more streamlined "Little Boy."', NULL, NULL, 2.1148, 6.166, 0, 1.02, '2026-07-15 16:46:47', '2026-07-15 16:46:47');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2639, 266856, 'tt2980516', NULL, 'The Theory of Everything', 'The Theory of Everything', 'movie', 2014, 'https://image.tmdb.org/t/p/w500/7kwcLFNt887saoQAL7EY0XnW7VI.jpg', 'https://image.tmdb.org/t/p/original/dh2QT3TPtAQf057yeLpNMuaJlmp.jpg', 'Once a healthy, active young man, Hawking received an earth-shattering diagnosis at 21 years of age. With Jane fighting tirelessly by his side, Stephen embarks on his most ambitious scientific work, studying the very thing he now has precious little of – time.', NULL, NULL, 5.2886, 7.83, 0, 1.02, '2026-07-15 16:46:47', '2026-07-15 16:46:47');
UPDATE "recommendations" SET "tmdb_id"=453, "imdb_id"='tt0268978', "igdb_id"=NULL, "title"='A Beautiful Mind', "original_title"='A Beautiful Mind', "media_type"='movie', "release_year"=2001, "poster_url"='https://image.tmdb.org/t/p/w500/rEIg5yJdNOt9fmX4P8gU9LeNoTQ.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/hCJFWTPghXCwwSpvPpAoIB8318Q.jpg', "overview"='From the heights of notoriety to the depths of depravity, John Forbes Nash Jr. experiences it all. As a brilliant but socially awkward mathematician, he made a groundbreaking discovery early in his career and stands on the brink of international acclaim. But as the handsome and arrogant Nash accepts secret work in cryptography, he becomes entangled in a mysterious conspiracy. His life takes a nightmarish turn and he soon finds himself on a painful and harrowing journey of self-discovery.', "external_url"=NULL, "platforms"=NULL, "popularity"=9.6654, "vote_average"=7.855, "is_ambiguous"=0, "evidence_score"=7.15, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-15 16:46:47' WHERE "id"=2383;
UPDATE "recommendations" SET "tmdb_id"=568, "imdb_id"='tt0112384', "igdb_id"=NULL, "title"='Apollo 13', "original_title"='Apollo 13', "media_type"='movie', "release_year"=1995, "poster_url"='https://image.tmdb.org/t/p/w500/tVeKscCm2fY1xDXZk8PgnZ87h9S.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/n0FDJI9c0uWiZwm8wgXVjaMBn96.jpg', "overview"='The true story of technical troubles that scuttle the Apollo 13 lunar mission in 1970, risking the lives of astronaut Jim Lovell and his crew, with the failed journey turning into a thrilling saga of heroism. Drifting more than 200,000 miles from Earth, the astronauts work furiously with the ground crew to avert tragedy.', "external_url"=NULL, "platforms"=NULL, "popularity"=6.6124, "vote_average"=7.5, "is_ambiguous"=0, "evidence_score"=6.51, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-15 16:46:47' WHERE "id"=2396;
